module asyn_fifo #(
    parameter DEPTH = 16,
    parameter WIDTH = 8
) (
    input wclk, rclk, wrstn, rrstn, winc, rinc,
    input [WIDTH-1:0] wdata,
    output reg wfull, rempty,
    output reg [WIDTH-1:0] rdata
);

reg [$clog2(DEPTH)-1:0] waddr, raddr;
wire [WIDTH-1:0] ram_rdata;
reg [DEPTH-1:0] ram_ren, ram_wen;

always @(posedge wclk) begin
    if (ram_wen[waddr]) begin
        ram_rdata[waddr] <= wdata;
    end
end

always @(posedge rclk) begin
    if (ram_ren[raddr]) begin
        rdata <= ram_rdata;
    end
end

always @(posedge wclk or negedge wrstn) begin
    if (!wrstn) begin
        waddr <= 0;
        wfull <= 0;
    end else if (winc && !wfull) begin
        waddr <= waddr + 1;
        wfull <= (waddr == raddr);
    end
end

always @(posedge rclk or negedge rrstn) begin
    if (!rrstn) begin
        raddr <= 0;
        rempty <= 1;
    end else if (rinc && !rempty) begin
        raddr <= raddr + 1;
        rempty <= (raddr == waddr);
    end
end

always @(posedge wclk) begin
    ram_wen[waddr] <= winc && !wfull;
end

always @(posedge rclk) begin
    ram_ren[raddr] <= rinc && !rempty;
end

endmodule
